if (! function_exists('hn_top_stories')) {
    function hn_top_stories($count = null, $details = null, $store_db = null, $timeout = null)
    {
        // HackerNews Top Stories — fetch community data from HN API
        $count = $count ?? 30;
        $details = $details ?? true;
        $store_db = $store_db ?? '';
        $timeout = $timeout ?? 20;

        $count = max(1, min(100, (int)$count));
        $timeout = max(5, min(30, (int)$timeout));

        $base = 'https://hacker-news.firebaseio.com/v0';

        // Helper: fetch JSON
        function hn_fetch($url, $timeout) {
            $ctx = stream_context_create([
                'http' => ['method' => 'GET', 'timeout' => $timeout, 'header' => "User-Agent: hn_top_stories/1.0\r\n", 'ignore_errors' => true],
                'ssl' => ['verify_peer' => false, 'verify_peer_name' => false],
            ]);
            $body = @file_get_contents($url, false, $ctx);
            if ($body === false) return ['error' => 'fetch failed', 'success' => false];
            $status = 200;
            if (isset($http_response_header)) {
                foreach ($http_response_header as $h) {
                    if (preg_match('#^HTTP/\d+\.\d+ (\d+)#', $h, $m)) { $status = (int)$m[1]; break; }
                }
            }
            $data = @json_decode($body, true);
            if ($data === null) return ['error' => 'Invalid JSON', 'success' => false];
            return ['data' => $data, 'status' => $status, 'success' => true];
        }

        // 1. Fetch top story IDs
        $ids_result = hn_fetch("$base/topstories.json", $timeout);
        if (!$ids_result['success']) {
            return ['error' => 'Failed to fetch top story IDs: ' . ($ids_result['error'] ?? 'unknown'), 'success' => false];
        }

        $all_ids = $ids_result['data'];
        if (!is_array($all_ids) || empty($all_ids)) {
            return ['error' => 'No story IDs returned from HN API', 'success' => false];
        }

        $story_ids = array_slice($all_ids, 0, $count);
        $total_available = count($all_ids);

        // 2. Fetch story details
        $stories = [];
        $errors = 0;

        foreach ($story_ids as $id) {
            $item = hn_fetch("$base/item/$id.json", $timeout);
            if (!$item['success'] || !is_array($item['data'])) {
                $errors++;
                continue;
            }
            $s = $item['data'];
            
            // Convert timestamp
            $ts = $s['time'] ?? 0;
            $datetime = $ts ? gmdate('Y-m-d\TH:i:s\Z', $ts) : '';
            $time_ago = '';
            if ($ts > 0) {
                $diff = time() - $ts;
                if ($diff < 3600) $time_ago = floor($diff / 60) . 'm ago';
                elseif ($diff < 86400) $time_ago = floor($diff / 3600) . 'h ago';
                else $time_ago = floor($diff / 86400) . 'd ago';
            }
            
            $stories[] = [
                'id' => $id,
                'title' => $s['title'] ?? '[deleted]',
                'url' => $s['url'] ?? "https://news.ycombinator.com/item?id=$id",
                'type' => $s['type'] ?? 'story',
                'score' => $s['score'] ?? 0,
                'author' => $s['by'] ?? '[deleted]',
                'comment_count' => $s['descendants'] ?? 0,
                'timestamp' => $datetime,
                'time_ago' => $time_ago,
            ];
            
            // Small delay to avoid rate limiting
            if (count($stories) < $count) usleep(50000); // 50ms
        }

        // 3. Optionally store in SQLite
        $stored = false;
        if (!empty($store_db)) {
            $db_path = __DIR__ . '/../workspace/' . basename($store_db);
            $db_dir = dirname($db_path);
            if (!is_dir($db_dir)) @mkdir($db_dir, 0777, true);
            
            try {
                $pdo = new PDO("sqlite:$db_path");
                $pdo->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
                $pdo->exec("CREATE TABLE IF NOT EXISTS hn_stories (
                    id INTEGER PRIMARY KEY,
                    title TEXT, url TEXT, type TEXT,
                    score INTEGER, author TEXT,
                    comment_count INTEGER, fetched_at TEXT
                )");
                
                $ins = $pdo->prepare("INSERT OR REPLACE INTO hn_stories (id, title, url, type, score, author, comment_count, fetched_at) VALUES (?, ?, ?, ?, ?, ?, ?, ?)");
                $now = gmdate('Y-m-d\TH:i:s\Z');
                foreach ($stories as $s) {
                    $ins->execute([$s['id'], $s['title'], $s['url'], $s['type'], $s['score'], $s['author'], $s['comment_count'], $now]);
                }
                $stored = true;
            } catch (Exception $e) {
                // Storage is optional, don't fail the request
            }
        }

        // Summary stats
        $total_score = array_sum(array_column($stories, 'score'));
        $total_comments = array_sum(array_column($stories, 'comment_count'));

        return [
            'success' => true,
            'source' => 'HackerNews API (Firebase)',
            'fetched_at' => gmdate('Y-m-d\TH:i:s\Z'),
            'total_available' => $total_available,
            'stories_returned' => count($stories),
            'fetch_errors' => $errors,
            'summary' => [
                'total_score' => $total_score,
                'avg_score' => count($stories) > 0 ? round($total_score / count($stories), 1) : 0,
                'total_comments' => $total_comments,
                'top_story' => $stories[0]['title'] ?? '',
                'top_score' => $stories[0]['score'] ?? 0,
            ],
            'stories' => $stories,
            'stored_in_db' => $stored ? $store_db : false,
            'query_hint' => $stored ? "sqlite_query db_name=\"$store_db\" sql=\"SELECT * FROM hn_stories ORDER BY score DESC\"" : '',
        ];
    }
}
